package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Iterator;
import java.util.Map;

class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;
    private JsonObject jsonObject;

    @BeforeEach
    void setUp() throws Exception {
        jsonObject = new JsonObject();
        jsonObject.addProperty("key1", "value1");
        jsonObject.addProperty("key2", "value2");

        jsonTreeReader = new JsonTreeReader(jsonObject);

        // Use reflection to set stack and stackSize to simulate peekStack returning jsonObject
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stackArray = (Object[]) stackField.get(jsonTreeReader);
        stackArray[0] = jsonObject;
        stackField.set(jsonTreeReader, stackArray);

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 1);
    }

    @Test
    void beginObject_success() throws Exception {
        // Spy on jsonTreeReader to intercept private expect method via reflection
        JsonTreeReader spyReader = spy(jsonTreeReader);

        // Use reflection to get private expect method
        Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
        expectMethod.setAccessible(true);

        // Stub expect method to do nothing when called with BEGIN_OBJECT
        doAnswer(invocation -> null).when(spyReader).expect(JsonToken.BEGIN_OBJECT);

        // Invoke beginObject via reflection
        Method beginObjectMethod = JsonTreeReader.class.getDeclaredMethod("beginObject");
        beginObjectMethod.setAccessible(true);
        beginObjectMethod.invoke(spyReader);

        // Verify expect called with BEGIN_OBJECT by invoking expect and catching no exception
        verify(spyReader, times(1)).expect(JsonToken.BEGIN_OBJECT);

        // Verify stack has new top as iterator of jsonObject.entrySet()
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stackArray = (Object[]) stackField.get(spyReader);

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        int stackSize = stackSizeField.getInt(spyReader);

        assertEquals(2, stackSize);

        Object top = stackArray[stackSize - 1];
        assertTrue(top instanceof Iterator);

        @SuppressWarnings("unchecked")
        Iterator<Map.Entry<String, JsonElement>> iterator = (Iterator<Map.Entry<String, JsonElement>>) top;
        assertTrue(iterator.hasNext());
        Map.Entry<String, JsonElement> entry = iterator.next();
        assertEquals("key1", entry.getKey());
        assertEquals("value1", entry.getValue().getAsString());
    }

    @Test
    void beginObject_expectThrowsIOException() throws Exception {
        JsonTreeReader spyReader = spy(jsonTreeReader);

        // Use reflection to get private expect method
        Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
        expectMethod.setAccessible(true);

        // Stub expect method to throw IOException when called with BEGIN_OBJECT
        doThrow(new IOException("Expected exception")).when(spyReader).expect(JsonToken.BEGIN_OBJECT);

        Method beginObjectMethod = JsonTreeReader.class.getDeclaredMethod("beginObject");
        beginObjectMethod.setAccessible(true);

        IOException thrown = assertThrows(IOException.class, () -> {
            try {
                beginObjectMethod.invoke(spyReader);
            } catch (Exception e) {
                // unwrap InvocationTargetException if present
                Throwable cause = e.getCause();
                if (cause instanceof IOException) {
                    throw (IOException) cause;
                }
                throw e;
            }
        });
        assertTrue(thrown.getMessage().contains("Expected exception"));
    }

    @Test
    void beginObject_stackTopNotJsonObjectClassCastException() throws Exception {
        // Set stack top to an object not JsonObject to cause ClassCastException
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stackArray = (Object[]) stackField.get(jsonTreeReader);
        stackArray[0] = "not a JsonObject";
        stackField.set(jsonTreeReader, stackArray);

        Method beginObjectMethod = JsonTreeReader.class.getDeclaredMethod("beginObject");
        beginObjectMethod.setAccessible(true);

        IOException thrown = assertThrows(IOException.class, () -> {
            try {
                beginObjectMethod.invoke(jsonTreeReader);
            } catch (Exception e) {
                Throwable cause = e.getCause();
                if (cause instanceof ClassCastException) {
                    throw new IOException(cause);
                }
                throw e;
            }
        });
        // The cause of IOException is ClassCastException
        assertTrue(thrown.getCause() instanceof ClassCastException);
    }
}

